import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';

const NavbarContainer = styled(motion.nav)`
  position: fixed;
  top: 2rem;
  left: 50%;
  transform: translateX(-50%);
  width: fit-content;
  background: rgba(10, 10, 15, 0.4);
  backdrop-filter: blur(30px) saturate(200%);
  padding: 0.6rem 1rem;
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 1000;
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 100px;
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.4),
              inset 0 1px 1px rgba(255, 255, 255, 0.1);

  &::before {
    content: '';
    position: absolute;
    inset: -2px;
    border-radius: 100px;
    padding: 2px;
    background: linear-gradient(90deg, 
      transparent 0%, 
      rgba(0, 242, 254, 0.4) 25%, 
      rgba(112, 40, 228, 0.4) 75%, 
      transparent 100%);
    -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
    -webkit-mask-composite: xor;
    mask-composite: exclude;
    pointer-events: none;
  }
`;

const LogoWrapper = styled(motion.div)`
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 0 1.5rem;
  border-right: 1px solid rgba(255, 255, 255, 0.1);
  cursor: pointer;
`;

const Logo = styled.div`
  font-size: 1.4rem;
  font-weight: 950;
  letter-spacing: -2px;
  background: linear-gradient(135deg, #00f2fe 0%, #4facfe 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  text-transform: uppercase;
  filter: drop-shadow(0 0 10px rgba(0, 242, 254, 0.5));
`;

const NavLinks = styled.div`
  display: flex;
  gap: 0.5rem;
  align-items: center;
  padding: 0 1rem;
`;

const NavItem = styled(motion.div)`
  position: relative;
`;

const NavLink = styled(Link)`
  color: rgba(255, 255, 255, 0.6);
  text-decoration: none;
  padding: 0.7rem 1.2rem;
  border-radius: 100px;
  transition: all 0.3s ease;
  font-weight: 700;
  font-size: 0.8rem;
  letter-spacing: 1px;
  text-transform: uppercase;
  display: block;

  &:hover {
    color: #fff;
  }

  &.active {
    color: #00f2fe;
  }
`;

const GlowIndicator = styled(motion.div)`
  position: absolute;
  bottom: -4px;
  left: 50%;
  transform: translateX(-50%);
  width: 4px;
  height: 4px;
  background: #00f2fe;
  border-radius: 50%;
  box-shadow: 0 0 10px #00f2fe, 0 0 20px #00f2fe;
`;

const ActionWrapper = styled.div`
  padding-left: 1rem;
  border-left: 1px solid rgba(255, 255, 255, 0.1);
  display: flex;
  gap: 0.5rem;
`;

const GlassButton = styled(motion.button)`
  background: rgba(255, 255, 255, 0.05);
  color: #fff;
  border: 1px solid rgba(255, 255, 255, 0.1);
  padding: 0.6rem 1.4rem;
  border-radius: 100px;
  font-weight: 800;
  cursor: pointer;
  font-size: 0.75rem;
  letter-spacing: 1px;
  text-transform: uppercase;
  transition: all 0.3s ease;

  &:hover {
    background: rgba(255, 255, 255, 0.1);
    border-color: rgba(255, 255, 255, 0.3);
    box-shadow: 0 0 20px rgba(255, 255, 255, 0.1);
  }
`;

const PrimaryButton = styled(GlassButton)`
  background: linear-gradient(135deg, #00f2fe 0%, #4facfe 100%);
  color: #000;
  border: none;
  box-shadow: 0 0 20px rgba(0, 242, 254, 0.3);

  &:hover {
    box-shadow: 0 0 30px rgba(0, 242, 254, 0.5);
    transform: scale(1.05);
  }
`;

const Navbar: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const navItems = [
    { path: '/', label: 'Core' },
    { path: '/feeds', label: 'Feeds' },
    { path: '/gold-silver', label: 'Metals' },
    { path: '/vectors', label: 'Vectors' },
  ];
  if (user) {
    navItems.push({ path: '/portfolio', label: 'VAULT' });
    navItems.push({ path: '/logout', label: 'TERMINATE' });
  } else {
    navItems.push({ path: '/initialize', label: 'INITIALIZE' });
  }

  const handleNavClick = (path: string) => {
    if (path === '/logout') {
      logout();
      navigate('/');
    }
  };

  return (
    <NavbarContainer
      initial={{ y: -100, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ type: 'spring', stiffness: 100, damping: 20 }}
    >
      <LogoWrapper 
        onClick={() => navigate('/')}
        whileHover={{ scale: 1.05 }}
      >
        <Logo>ZEUS</Logo>
      </LogoWrapper>

      <NavLinks>
        {navItems.map((item) => (
          <NavItem key={item.path}>
            <NavLink
              to={item.path === '/logout' ? '#' : item.path}
              className={location.pathname === item.path ? 'active' : ''}
              onClick={() => handleNavClick(item.path)}
              style={item.path === '/initialize' ? { background: 'linear-gradient(135deg, #00f2fe 0%, #4facfe 100%)', color: '#000', padding: '0.7rem 1.5rem', marginLeft: '0.5rem' } : {}}
            >
              {item.label}
            </NavLink>
            {location.pathname === item.path && item.path !== '/logout' && (
              <GlowIndicator
                layoutId="nav-glow"
                transition={{ type: 'spring', stiffness: 300, damping: 30 }}
              />
            )}
          </NavItem>
        ))}
      </NavLinks>
    </NavbarContainer>
  );
};

export default Navbar;
